document.addEventListener('DOMContentLoaded', () => {
  const spendSection = document.querySelector('.spend-section');
  const summarySection = document.querySelector('.summary-section');
  const fleetSection = document.querySelector('.fleet-section');
  const currentBalanceEl = document.getElementById('current-balance');
  const transactionList = document.getElementById('transaction-list');
  const carListEl = document.getElementById('car-list');
  const purchasedCarListEl = document.getElementById('purchased-car-list');

  const authHeader = 'Basic ' + btoa('admin:securepassword');

  let balance = 0;
  let transactions = [];
  let purchasedCars = [];
  let cars = []; // Will be fetched from backend purchases or API

  async function fetchEarningsFromBackend() {
    try {
      console.log('Fetching earnings from backend...');
      const response = await fetch('/api/earnings', {
        headers: { 'Authorization': authHeader },
        credentials: 'include'
      });
      console.log('Fetch response status:', response.status);
      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }
      const data = await response.json();
      console.log('Earnings data received:', data);
      balance = data.totalAnnualRevenue;
      transactions = []; // Backend does not provide generic transactions, so keep empty or could be enhanced
      purchasedCars = data.purchases.autoFleetDetails || [];
      renderBalance();
      renderPurchasedCars();
      spendSection.style.display = 'block';
      summarySection.style.display = 'block';
      fleetSection.style.display = 'block';
    } catch (error) {
      console.error('Failed to fetch earnings from backend:', error);
      alert('Failed to load earnings data. Please try again later.');
    }
  }

  function renderBalance() {
    currentBalanceEl.textContent = balance.toFixed(2);
  }

  function renderTransactions() {
    transactionList.innerHTML = '';
    transactions.forEach((t, index) => {
      const li = document.createElement('li');
      li.textContent = `${t.description} - $${t.amount.toFixed(2)} [${t.category}]`;

      const deleteBtn = document.createElement('button');
      deleteBtn.textContent = 'Delete';
      deleteBtn.style.marginLeft = '1rem';
      deleteBtn.addEventListener('click', () => {
        transactions.splice(index, 1);
        updateBalance();
        renderTransactions();
      });

      li.appendChild(deleteBtn);
      transactionList.appendChild(li);
    });
  }

  async function fetchCarsFromBackend() {
    // For now, use purchasedCars as cars available for purchase is not provided by backend
    // Alternatively, could fetch from external API or backend endpoint if available
    // Here, we simulate cars available for purchase by filtering out purchased cars from a static list or empty list
    // For demo, we use a static list of cars
    cars = [
      { model: 'Tesla Model S', price: 79999 },
      { model: 'BMW X5', price: 60999 },
      { model: 'Audi Q7', price: 54999 }
    ];
    // Remove cars already purchased by VIN or model if VIN not available
    const purchasedModels = new Set(purchasedCars.map(car => car.model));
    cars = cars.filter(car => !purchasedModels.has(car.model));
    renderCarList();
  }

  function updateBalance() {
    // Balance is managed by backend, so here just re-render
    renderBalance();
  }

  function renderCarList() {
    carListEl.innerHTML = '';
    cars.forEach((car) => {
      const li = document.createElement('li');
      li.textContent = `${car.model} - $${car.price.toFixed(2)}`;

      const purchaseBtn = document.createElement('button');
      purchaseBtn.textContent = 'Purchase';
      purchaseBtn.style.marginLeft = '1rem';
      purchaseBtn.addEventListener('click', async () => {
        if (car.price > balance) {
          alert('Insufficient balance to purchase this car.');
          return;
        }
        // Call backend API to purchase auto fleet
        const vin = 'VIN-' + Math.floor(Math.random() * 1000000); // Generate dummy VIN
        const dealership = 'Default Dealership'; // Placeholder
        try {
          const response = await fetch('/api/purchase/auto', {
            method: 'POST',
            headers: {
              'Content-Type': 'application/json',
              'Authorization': authHeader
            },
            body: JSON.stringify({
              cost: car.price,
              model: car.model,
              vin,
              dealership
            })
          });
          const result = await response.json();
          if (response.ok) {
            alert(result.message);
            balance = result.remainingRevenue;
            purchasedCars.push({
              model: car.model,
              vin,
              dealership,
              cost: car.price,
              purchaseDate: new Date().toISOString(),
              deliveryStatus: 'pending',
              deliveryDate: null,
              deliveryAddress: null
            });
            cars = cars.filter(c => c.model !== car.model);
            renderBalance();
            renderCarList();
            renderPurchasedCars();
          } else {
            alert('Error: ' + result.error);
          }
        } catch (error) {
          alert('Failed to make purchase: ' + error.message);
        }
      });

      li.appendChild(purchaseBtn);
      carListEl.appendChild(li);
    });
  }

  function renderPurchasedCars() {
    purchasedCarListEl.innerHTML = '';
    purchasedCars.forEach((car) => {
      const li = document.createElement('li');
      li.textContent = `${car.model} - $${car.cost.toFixed(2)} (VIN: ${car.vin})`;
      purchasedCarListEl.appendChild(li);
    });
  }

  // Remove local spend form and transactions as backend does not support generic spending transactions
  // Optionally, could implement backend API for generic spending if needed

  // Initialize UI by fetching earnings and cars from backend
  fetchEarningsFromBackend().then(() => {
    fetchCarsFromBackend();
  });
});

/**
 * JPMorgan Authentication Integration
 * Integrates Oscar Broome Login Override System with JPMorgan Payment System
 */

const jwt = require('jsonwebtoken');
const crypto = require('node:crypto');
const bcrypt = require('bcrypt');
const winston = require('winston');

// Configuration
const config = {
  jwt: {
    secret: process.env.JWT_SECRET || crypto.randomBytes(64).toString('hex'),
    refreshSecret: process.env.JWT_REFRESH_SECRET || crypto.randomBytes(64).toString('hex'),
    expiresIn: '15m',
    refreshExpiresIn: '7d'
  },
  mfa: {
    secret: process.env.MFA_SECRET || crypto.randomBytes(32).toString('hex')
  },
  security: {
    maxLoginAttempts: 5,
    lockoutTime: 15 * 60 * 1000, // 15 minutes
    adminOverrideCode: process.env.ADMIN_OVERRIDE_CODE || 'OSCAR_BROOME_EMERGENCY_2024'
  }
};

// In-memory stores (use database in production)
const users = new Map();
const sessions = new Map();
const loginAttempts = new Map();
const overrideCodes = new Map();

// Logger setup
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  transports: [
    new winston.transports.Console(),
    new winston.transports.File({ filename: 'auth.log' })
  ]
});

class JPMorganAuthManager {
  constructor() {
    this.initializeDefaultUsers();
  }

  // Password hashing using bcrypt (replacing hashlib)
  async hashPassword(password) {
    const saltRounds = 12;
    return await bcrypt.hash(password, saltRounds);
  }

  // Password verification
  async verifyPassword(password, hashedPassword) {
    try {
      return await bcrypt.compare(password, hashedPassword);
    } catch (error) {
      logger.error('Password verification error:', error);
      return false;
    }
  }

  // Password validation
  validatePassword(password) {
    if (!password || password.length < 8 || password.length > 128) {
      return { valid: false, message: 'Password must be 8-128 characters long' };
    }

    const hasUpper = /[A-Z]/.test(password);
    const hasLower = /[a-z]/.test(password);
    const hasDigit = /\d/.test(password);
    const hasSpecial = /[!@#$%^&*()_+\-={}|;:,.<>?`~]/.test(password);

    if (!(hasUpper && hasLower && hasDigit && hasSpecial)) {
      return {
        valid: false,
        message: 'Password must contain uppercase, lowercase, digit, and special character'
      };
    }

    return { valid: true, message: 'Password is valid' };
  }

  // Initialize default users
  async initializeDefaultUsers() {
    try {
      // Admin user
      const adminPassword = await this.hashPassword('OscarBroome2024!');
      users.set('admin@jpmorgan.oscarbroomerevenue.com', {
        id: 'admin-jpm-001',
        email: 'admin@jpmorgan.oscarbroomerevenue.com',
        password: adminPassword,
        role: 'admin',
        mfaEnabled: true,
        mfaSecret: config.mfa.secret,
        lastLogin: null,
        loginAttempts: 0,
        locked: false,
        lockedUntil: null,
        permissions: ['read', 'write', 'delete', 'admin', 'jpmorgan_payments'],
        department: 'JPMorgan Integration'
      });

      // Executive user
      const execPassword = await this.hashPassword('Executive2024!');
      users.set('executive@jpmorgan.oscarbroomerevenue.com', {
        id: 'exec-jpm-001',
        email: 'executive@jpmorgan.oscarbroomerevenue.com',
        password: execPassword,
        role: 'executive',
        mfaEnabled: true,
        mfaSecret: crypto.randomBytes(32).toString('hex'),
        lastLogin: null,
        loginAttempts: 0,
        locked: false,
        lockedUntil: null,
        permissions: ['read', 'write', 'jpmorgan_payments'],
        department: 'JPMorgan Integration'
      });

      logger.info('JPMorgan authentication users initialized');
    } catch (error) {
      logger.error('Error initializing users:', error);
    }
  }

  // User authentication
  async authenticateUser(email, password, mfaCode = null) {
    // Check rate limiting
    if (this.isAccountLocked(email)) {
      logger.warning(`Login attempt for locked account: ${email}`);
      return {
        success: false,
        message: 'Account is temporarily locked due to too many failed attempts'
      };
    }

    const user = users.get(email);
    if (!user) {
      logger.warning(`Login attempt for non-existent user: ${email}`);
      this.recordFailedAttempt(email);
      return { success: false, message: 'Invalid credentials' };
    }

    // Verify password
    const isValidPassword = await this.verifyPassword(password, user.password);
    if (!isValidPassword) {
      logger.warning(`Invalid password for user: ${email}`);
      this.recordFailedAttempt(email);
      return { success: false, message: 'Invalid credentials' };
    }

    // Check MFA if enabled
    if (user.mfaEnabled) {
      if (!mfaCode) {
        return {
          success: false,
          message: 'MFA code required',
          requiresMfa: true
        };
      }

      if (!this.verifyMfaCode(user.mfaSecret, mfaCode)) {
        logger.warning(`Invalid MFA code for user: ${email}`);
        this.recordFailedAttempt(email);
        return { success: false, message: 'Invalid MFA code' };
      }
    }

    // Reset login attempts on successful login
    user.loginAttempts = 0;
    user.lastLogin = new Date().toISOString();
    users.set(email, user);

    // Generate tokens
    const tokens = this.generateTokens(user);

    // Store session
    sessions.set(tokens.accessToken, {
      userId: user.id,
      email: user.email,
      role: user.role,
      permissions: user.permissions,
      department: user.department,
      expiresAt: Date.now() + (15 * 60 * 1000) // 15 minutes
    });

    logger.info(`Successful login for JPMorgan user: ${email}`);
    return {
      success: true,
      message: 'Login successful',
      user: {
        id: user.id,
        email: user.email,
        role: user.role,
        permissions: user.permissions,
        department: user.department
      },
      tokens
    };
  }

  // Admin override
  async adminOverride(overrideCode, targetEmail) {
    if (overrideCode !== config.security.adminOverrideCode) {
      logger.warning('Invalid admin override code attempt');
      return { success: false, message: 'Invalid override code' };
    }

    const user = users.get(targetEmail);
    if (!user) {
      logger.warning(`Admin override for non-existent user: ${targetEmail}`);
      return { success: false, message: 'User not found' };
    }

    // Reset user account
    user.loginAttempts = 0;
    user.locked = false;
    user.lockedUntil = null;
    users.set(targetEmail, user);

    // Generate emergency access token
    const emergencyToken = jwt.sign(
      {
        userId: user.id,
        email: user.email,
        role: user.role,
        permissions: user.permissions,
        department: user.department,
        override: true,
        emergency: true,
        exp: Math.floor(Date.now() / 1000) + (60 * 60) // 1 hour
      },
      config.jwt.secret
    );

    logger.info(`Admin override successful for JPMorgan user: ${targetEmail}`);
    return {
      success: true,
      message: 'Admin override successful',
      emergencyToken,
      user: {
        id: user.id,
        email: user.email,
        role: user.role,
        department: user.department
      }
    };
  }

  // Token generation
  generateTokens(user) {
    const accessToken = jwt.sign(
      {
        userId: user.id,
        email: user.email,
        role: user.role,
        permissions: user.permissions,
        department: user.department,
        exp: Math.floor(Date.now() / 1000) + (15 * 60) // 15 minutes
      },
      config.jwt.secret
    );

    const refreshToken = jwt.sign(
      {
        userId: user.id,
        email: user.email,
        type: 'refresh',
        exp: Math.floor(Date.now() / 1000) + (7 * 24 * 60 * 60) // 7 days
      },
      config.jwt.refreshSecret
    );

    return { accessToken, refreshToken };
  }

  // Token verification
  verifyToken(token) {
    try {
      const decoded = jwt.verify(token, config.jwt.secret);
      const session = sessions.get(token);

      if (!session || session.expiresAt < Date.now()) {
        return null;
      }

      return decoded;
    } catch (error) {
      return null;
    }
  }

  // MFA verification (simplified TOTP)
  verifyMfaCode(secret, code) {
    const timeWindow = Math.floor(Date.now() / 30000); // 30-second windows
    const expectedCode = (timeWindow % 1000000).toString().padStart(6, '0');
    return expectedCode === code;
  }

  // Rate limiting
  recordFailedAttempt(email) {
    const attempts = loginAttempts.get(email) || { count: 0, lastAttempt: Date.now() };
    attempts.count += 1;
    attempts.lastAttempt = Date.now();

    if (attempts.count >= config.security.maxLoginAttempts) {
      const user = users.get(email);
      if (user) {
        user.locked = true;
        user.lockedUntil = Date.now() + config.security.lockoutTime;
        users.set(email, user);
        logger.warning(`Account locked for JPMorgan user: ${email}`);
      }
    }

    loginAttempts.set(email, attempts);
  }

  // Account lock check
  isAccountLocked(email) {
    const user = users.get(email);
    if (!user || !user.locked) {
      return false;
    }

    if (Date.now() > user.lockedUntil) {
      user.locked = false;
      users.set(email, user);
      return false;
    }

    return true;
  }

  // Token refresh
  async refreshToken(refreshToken) {
    try {
      const decoded = jwt.verify(refreshToken, config.jwt.refreshSecret);
      const user = users.get(decoded.email);

      if (!user) {
        return { success: false, message: 'User not found' };
      }

      const tokens = this.generateTokens(user);
      return { success: true, tokens };
    } catch (error) {
      return { success: false, message: 'Invalid refresh token' };
    }
  }

  // Logout
  logout(token) {
    sessions.delete(token);
    logger.info('JPMorgan user logged out');
    return { success: true, message: 'Logged out successfully' };
  }

  // Get user profile
  getUserProfile(email) {
    const user = users.get(email);
    if (!user) {
      return null;
    }

    return {
      id: user.id,
      email: user.email,
      role: user.role,
      permissions: user.permissions,
      department: user.department,
      lastLogin: user.lastLogin,
      mfaEnabled: user.mfaEnabled
    };
  }

  // Session cleanup
  cleanupExpiredSessions() {
    const now = Date.now();
    const expiredTokens = [];

    for (const [token, session] of sessions) {
      if (session.expiresAt < now) {
        expiredTokens.push(token);
      }
    }

    for (const token of expiredTokens) {
      sessions.delete(token);
    }
    return { success: true, cleaned: expiredTokens.length };
  }

  // Force logout all sessions for user
  forceLogoutAll(userId) {
    const expiredTokens = [];

    for (const [token, session] of sessions) {
      if (session.userId === userId) {
        expiredTokens.push(token);
      }
    }

    expiredTokens.forEach(token => sessions.delete(token));
    return { success: true, loggedOut: expiredTokens.length };
  }
}

// Create singleton instance
const jpmorganAuthManager = new JPMorganAuthManager();

// Express middleware for JPMorgan authentication
const jpmorganAuthMiddleware = (requiredPermissions = []) => {
  return (req, res, next) => {
    try {
      const authHeader = req.headers.authorization;
      if (!authHeader || !authHeader.startsWith('Bearer ')) {
        return res.status(401).json({ error: 'Authorization token required' });
      }

      const token = authHeader.substring(7);
      const decoded = jpmorganAuthManager.verifyToken(token);

      if (!decoded) {
        return res.status(401).json({ error: 'Invalid or expired token' });
      }

      // Check permissions
      if (requiredPermissions.length > 0) {
        const userPermissions = decoded.permissions || [];
        const hasPermission = requiredPermissions.every(perm => userPermissions.includes(perm));

        if (!hasPermission) {
          return res.status(403).json({ error: 'Insufficient permissions' });
        }
      }

      req.user = decoded;
      next();
    } catch (error) {
      logger.error('Auth middleware error:', error);
      res.status(500).json({ error: 'Authentication error' });
    }
  };
};

// Admin override middleware
const jpmorganAdminMiddleware = (req, res, next) => {
  const user = req.user;
  if (!user || user.role !== 'admin') {
    return res.status(403).json({ error: 'Admin access required' });
  }
  next();
};

module.exports = {
  JPMorganAuthManager,
  jpmorganAuthManager,
  jpmorganAuthMiddleware,
  jpmorganAdminMiddleware,
  authenticateUser: (email, password, mfaCode) => jpmorganAuthManager.authenticateUser(email, password, mfaCode),
  adminOverride: (code, email) => jpmorganAuthManager.adminOverride(code, email),
  verifyToken: (token) => jpmorganAuthManager.verifyToken(token),
  refreshToken: (token) => jpmorganAuthManager.refreshToken(token),
  logout: (token) => jpmorganAuthManager.logout(token),
  getUserProfile: (email) => jpmorganAuthManager.getUserProfile(email)
};

/**
 * Oscar Broome Login Override System
 * Emergency access and administrative override capabilities
 */

import crypto from 'node:crypto';
import fs from 'node:fs';
import path from 'node:path';
import winston from 'winston';
import bcrypt from 'bcrypt';
import jwt from 'jsonwebtoken';
import { fileURLToPath } from 'node:url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

// Override logger
const overrideLogger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  defaultMeta: { service: 'login-override' },
  transports: [
    new winston.transports.File({ filename: 'logs/login_override.log' }),
    new winston.transports.Console({
      format: winston.format.combine(
        winston.format.colorize(),
        winston.format.simple()
      )
    })
  ]
});

// Standard authentication logger
const authLogger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  defaultMeta: { service: 'standard-auth' },
  transports: [
    new winston.transports.File({ filename: 'logs/auth.log' }),
    new winston.transports.Console({
      format: winston.format.combine(
        winston.format.colorize(),
        winston.format.simple()
      )
    })
  ]
});

// Override configuration
const OVERRIDE_CONFIG = {
  EMERGENCY_CODE: process.env.EMERGENCY_OVERRIDE_CODE || 'OSCAR_BROOME_EMERGENCY_2024',
  ADMIN_OVERRIDE_CODE: process.env.ADMIN_OVERRIDE_CODE || 'ADMIN_OVERRIDE_2024',
  MAX_OVERRIDE_ATTEMPTS: Number.parseInt(process.env.MAX_OVERRIDE_ATTEMPTS) || 3,
  OVERRIDE_WINDOW_MINUTES: Number.parseInt(process.env.OVERRIDE_WINDOW_MINUTES) || 15,
  REQUIRE_ADDITIONAL_AUTH: process.env.REQUIRE_ADDITIONAL_AUTH === 'true',
  NOTIFICATION_EMAILS: (process.env.NOTIFICATION_EMAILS || '').split(',').filter(email => email.trim()),
  // Enhanced security settings
  RATE_LIMIT_WINDOW_MS: Number.parseInt(process.env.RATE_LIMIT_WINDOW_MS) || 15 * 60 * 1000, // 15 minutes
  RATE_LIMIT_MAX_REQUESTS: Number.parseInt(process.env.RATE_LIMIT_MAX_REQUESTS) || 5,
  MFA_ENFORCEMENT_LEVEL: process.env.MFA_ENFORCEMENT_LEVEL || 'required', // 'required', 'optional', 'disabled'
  SESSION_TIMEOUT_MINUTES: Number.parseInt(process.env.SESSION_TIMEOUT_MINUTES) || 30,
  PASSWORD_MIN_LENGTH: Number.parseInt(process.env.PASSWORD_MIN_LENGTH) || 12,
  PASSWORD_REQUIRE_COMPLEXITY: process.env.PASSWORD_REQUIRE_COMPLEXITY !== 'false'
};

  // Override session storage
  const activeOverrides = new Map();
  const overrideAttempts = new Map();

  // Rate limiting storage
  const rateLimitStore = new Map();

// Override types
const OVERRIDE_TYPES = {
  EMERGENCY: 'emergency',
  ADMIN: 'admin',
  TECHNICAL: 'technical',
  SECURITY: 'security'
};

// Override reasons
const OVERRIDE_REASONS = {
  LOCKED_OUT: 'account_locked',
  MFA_FAILURE: 'mfa_failure',
  PASSWORD_RESET: 'password_reset',
  SYSTEM_MAINTENANCE: 'system_maintenance',
  EMERGENCY_ACCESS: 'emergency_access',
  TECHNICAL_ISSUE: 'technical_issue'
};

class LoginOverrideManager {
  constructor() {
    this.loadOverrideHistory();
  }

  // Emergency override for Oscar Broome
  async emergencyOverride(userId, reason, additionalAuth = null) {
    const overrideId = this.generateOverrideId();
    const timestamp = new Date().toISOString();

    // Validate emergency conditions
    if (!this.isCriticalReason(reason)) {
      throw new Error('Emergency override conditions not met');
    }

    // Check additional authentication if required
    if (OVERRIDE_CONFIG.REQUIRE_ADDITIONAL_AUTH && !additionalAuth) {
      throw new Error('Additional authentication required for emergency override');
    }

    // Create override session
    const overrideSession = {
      id: overrideId,
      type: OVERRIDE_TYPES.EMERGENCY,
      userId: userId,
      reason: reason,
      timestamp: timestamp,
      expiresAt: new Date(Date.now() + OVERRIDE_CONFIG.OVERRIDE_WINDOW_MINUTES * 60 * 1000).toISOString(),
      status: 'active',
      additionalAuth: additionalAuth,
      approvedBy: 'SYSTEM_EMERGENCY_PROTOCOL',
      notificationsSent: []
    };

    // Store override session
    activeOverrides.set(overrideId, overrideSession);

    // Log emergency override
    overrideLogger.warn('EMERGENCY OVERRIDE ACTIVATED', {
      overrideId,
      userId,
      reason,
      timestamp,
      expiresAt: overrideSession.expiresAt
    });

    // Send notifications
    await this.sendEmergencyNotifications(overrideSession);

    // Reset attempt counter
    overrideAttempts.delete(userId);

    return {
      success: true,
      overrideId,
      message: 'Emergency override activated for Oscar Broome',
      expiresAt: overrideSession.expiresAt,
      accessGranted: true
    };
  }

  // Administrative override
  async adminOverride(adminUserId, targetUserId, reason, justification) {
    const overrideId = this.generateOverrideId();
    const timestamp = new Date().toISOString();

    // Validate admin permissions
    if (!this.validateAdminPermissions(adminUserId)) {
      throw new Error('Insufficient admin permissions for override');
    }

    // Validate justification
    if (!justification || justification.length < 10) {
      throw new Error('Detailed justification required for admin override');
    }

    // Create override session
    const overrideSession = {
      id: overrideId,
      type: OVERRIDE_TYPES.ADMIN,
      adminUserId: adminUserId,
      targetUserId: targetUserId,
      reason: reason,
      justification: justification,
      timestamp: timestamp,
      expiresAt: new Date(Date.now() + OVERRIDE_CONFIG.OVERRIDE_WINDOW_MINUTES * 60 * 1000).toISOString(),
      status: 'active',
      approvedBy: adminUserId,
      notificationsSent: []
    };

    // Store override session
    activeOverrides.set(overrideId, overrideSession);

    // Log admin override
    overrideLogger.info('ADMIN OVERRIDE ACTIVATED', {
      overrideId,
      adminUserId,
      targetUserId,
      reason,
      justification,
      timestamp,
      expiresAt: overrideSession.expiresAt
    });

    // Send notifications
    await this.sendAdminNotifications(overrideSession);

    return {
      success: true,
      overrideId,
      message: 'Administrative override activated',
      expiresAt: overrideSession.expiresAt,
      accessGranted: true
    };
  }

  // Technical support override
  async technicalOverride(supportUserId, targetUserId, reason, ticketNumber) {
    const overrideId = this.generateOverrideId();
    const timestamp = new Date().toISOString();

    // Validate support permissions
    if (!this.validateSupportPermissions(supportUserId)) {
      throw new Error('Insufficient support permissions for override');
    }

    // Validate ticket number
    if (!ticketNumber || !/^[A-Z]{2,4}-\d{4,6}$/.test(ticketNumber)) {
      throw new Error('Valid support ticket number required');
    }

    // Create override session
    const overrideSession = {
      id: overrideId,
      type: OVERRIDE_TYPES.TECHNICAL,
      supportUserId: supportUserId,
      targetUserId: targetUserId,
      reason: reason,
      ticketNumber: ticketNumber,
      timestamp: timestamp,
      expiresAt: new Date(Date.now() + OVERRIDE_CONFIG.OVERRIDE_WINDOW_MINUTES * 60 * 1000).toISOString(),
      status: 'active',
      approvedBy: supportUserId,
      notificationsSent: []
    };

    // Store override session
    activeOverrides.set(overrideId, overrideSession);

    // Log technical override
    overrideLogger.info('TECHNICAL OVERRIDE ACTIVATED', {
      overrideId,
      supportUserId,
      targetUserId,
      reason,
      ticketNumber,
      timestamp,
      expiresAt: overrideSession.expiresAt
    });

    // Send notifications
    await this.sendTechnicalNotifications(overrideSession);

    return {
      success: true,
      overrideId,
      message: 'Technical support override activated',
      expiresAt: overrideSession.expiresAt,
      accessGranted: true
    };
  }

  // Validate override session
  validateOverrideSession(overrideId, userId) {
    const session = activeOverrides.get(overrideId);

    if (session) {
      if (session.status !== 'active') {
        return { valid: false, reason: 'Override session not active' };
      }

      if (new Date() > new Date(session.expiresAt)) {
        session.status = 'expired';
        activeOverrides.set(overrideId, session);
        return { valid: false, reason: 'Override session expired' };
      }

      if (session.targetUserId && session.targetUserId !== userId) {
        return { valid: false, reason: 'Override session not for this user' };
      }

      return {
        valid: true,
        session: session,
        type: session.type,
        expiresAt: session.expiresAt
      };
    } else {
      return { valid: false, reason: 'Override session not found' };
    }
  }

  // Revoke override session
  revokeOverride(overrideId, revokedBy, reason) {
    const session = activeOverrides.get(overrideId);

    if (!session) {
      throw new Error('Override session not found');
    }

    session.status = 'revoked';
    session.revokedBy = revokedBy;
    session.revokedAt = new Date().toISOString();
    session.revokeReason = reason;

    activeOverrides.set(overrideId, session);

    // Log revocation
    overrideLogger.warn('OVERRIDE SESSION REVOKED', {
      overrideId,
      revokedBy,
      reason,
      originalSession: session
    });

    // Send revocation notifications
    this.sendRevocationNotifications(session);

    return { success: true, message: 'Override session revoked' };
  }

  // Get active overrides for user
  getActiveOverrides(userId) {
    const userOverrides = [];

    for (const [overrideId, session] of activeOverrides) {
      if ((session.userId === userId || session.targetUserId === userId) &&
          session.status === 'active' &&
          new Date() < new Date(session.expiresAt)) {
        userOverrides.push({
          id: overrideId,
          type: session.type,
          reason: session.reason,
          expiresAt: session.expiresAt,
          approvedBy: session.approvedBy
        });
      }
    }

    return userOverrides;
  }

  // Check override attempts
  checkOverrideAttempts(userId) {
    const attempts = overrideAttempts.get(userId) || { count: 0, lastAttempt: null };
    const now = new Date();

    // Reset attempts if more than 1 hour has passed
    if (attempts.lastAttempt && (now - new Date(attempts.lastAttempt)) > 60 * 60 * 1000) {
      attempts.count = 0;
    }

    return attempts;
  }

  // Record override attempt
  recordOverrideAttempt(userId, success = false) {
    const attempts = this.checkOverrideAttempts(userId);
    attempts.lastAttempt = new Date().toISOString();

    if (!success) {
      attempts.count += 1;

      if (attempts.count >= OVERRIDE_CONFIG.MAX_OVERRIDE_ATTEMPTS) {
        overrideLogger.error('MAX OVERRIDE ATTEMPTS EXCEEDED', {
          userId,
          attempts: attempts.count,
          timestamp: attempts.lastAttempt
        });

        // Send security alert
        this.sendSecurityAlert(userId, 'max_override_attempts_exceeded');
      }
    } else {
      attempts.count = 0; // Reset on success
    }

    overrideAttempts.set(userId, attempts);
  }

  // Check if reason is critical
  isCriticalReason(reason) {
    const criticalReasons = [
      OVERRIDE_REASONS.EMERGENCY_ACCESS,
      OVERRIDE_REASONS.SYSTEM_MAINTENANCE,
      OVERRIDE_REASONS.TECHNICAL_ISSUE
    ];

    return criticalReasons.includes(reason);
  }

  // Validate admin permissions
  validateAdminPermissions(userId) {
    // Check if user has admin role
    const adminUsers = ['admin@oscarsystem.com', 'super_admin@oscarsystem.com'];
    return adminUsers.includes(userId);
  }

  // Validate support permissions
  validateSupportPermissions(userId) {
    // Check if user has support role
    const supportUsers = ['support@oscarsystem.com', 'tech@oscarsystem.com'];
    return supportUsers.includes(userId);
  }

  // Generate unique override ID
  generateOverrideId() {
    return `OVERRIDE_${Date.now()}_${crypto.randomBytes(4).toString('hex').toUpperCase()}`;
  }

  // Send emergency notifications
  async sendEmergencyNotifications(session) {
    const notifications = OVERRIDE_CONFIG.NOTIFICATION_EMAILS;

    for (const email of notifications) {
      // In a real implementation, this would send actual emails
      overrideLogger.info('EMERGENCY OVERRIDE NOTIFICATION SENT', {
        overrideId: session.id,
        email: email,
        type: 'emergency_override_activated'
      });
    }

    session.notificationsSent = notifications;
  }

  // Send admin notifications
  async sendAdminNotifications(session) {
    const notifications = OVERRIDE_CONFIG.NOTIFICATION_EMAILS;

    for (const email of notifications) {
      overrideLogger.info('ADMIN OVERRIDE NOTIFICATION SENT', {
        overrideId: session.id,
        email: email,
        type: 'admin_override_activated'
      });
    }

    session.notificationsSent = notifications;
  }

  // Send technical notifications
  async sendTechnicalNotifications(session) {
    const notifications = OVERRIDE_CONFIG.NOTIFICATION_EMAILS;

    for (const email of notifications) {
      overrideLogger.info('TECHNICAL OVERRIDE NOTIFICATION SENT', {
        overrideId: session.id,
        email: email,
        type: 'technical_override_activated'
      });
    }

    session.notificationsSent = notifications;
  }

  // Send revocation notifications
  sendRevocationNotifications(session) {
    const notifications = OVERRIDE_CONFIG.NOTIFICATION_EMAILS;

    for (const email of notifications) {
      overrideLogger.info('OVERRIDE REVOCATION NOTIFICATION SENT', {
        overrideId: session.id,
        email: email,
        type: 'override_revoked'
      });
    }
  }

  // Send security alert
  sendSecurityAlert(userId, alertType) {
    const notifications = OVERRIDE_CONFIG.NOTIFICATION_EMAILS;

    for (const email of notifications) {
      overrideLogger.error('SECURITY ALERT', {
        userId,
        alertType,
        email: email,
        timestamp: new Date().toISOString()
      });
    }
  }

  // Load override history from file
  loadOverrideHistory() {
    try {
      const historyPath = path.join(__dirname, '../logs/override_history.json');
      if (fs.existsSync(historyPath)) {
        const history = JSON.parse(fs.readFileSync(historyPath, 'utf-8'));
        // Restore active overrides from history
        for (const [id, session] of Object.entries(history.activeOverrides || {})) {
          if (session.status === 'active' && new Date() < new Date(session.expiresAt)) {
            activeOverrides.set(id, session);
          }
        }
      }
    } catch (error) {
      // Log error but don't rethrow - this is a utility method that should fail gracefully
      overrideLogger.error('Failed to load override history', { error: error.message });
    }
  }

  // Save override history to file
  saveOverrideHistory() {
    try {
      const historyPath = path.join(__dirname, '../logs/override_history.json');
      const history = {
        activeOverrides: Object.fromEntries(activeOverrides),
        lastUpdated: new Date().toISOString()
      };

      fs.writeFileSync(historyPath, JSON.stringify(history, null, 2), 'utf-8');
    } catch (error) {
      overrideLogger.error('Failed to save override history', { error: error.message });
    }
  }

  // Cleanup expired overrides
  cleanupExpiredOverrides() {
    const now = new Date();
    let cleaned = 0;

    for (const [id, session] of activeOverrides) {
      if (session.status === 'active' && now > new Date(session.expiresAt)) {
        session.status = 'expired';
        activeOverrides.set(id, session);
        cleaned++;
      }
    }

    if (cleaned > 0) {
      overrideLogger.info('Cleaned up expired overrides', { count: cleaned });
      this.saveOverrideHistory();
    }
  }

  // Get override statistics
  getOverrideStatistics() {
    const stats = {
      totalActive: 0,
      byType: {},
      byReason: {},
      recentActivity: []
    };

    for (const session of activeOverrides.values()) {
      if (session.status === 'active') {
        stats.totalActive++;
        stats.byType[session.type] = (stats.byType[session.type] || 0) + 1;
        stats.byReason[session.reason] = (stats.byReason[session.reason] || 0) + 1;
      }

      // Add to recent activity (last 24 hours)
      const sessionTime = new Date(session.timestamp);
      const oneDayAgo = new Date(Date.now() - 24 * 60 * 60 * 1000);

      if (sessionTime > oneDayAgo) {
        stats.recentActivity.push({
          id: session.id,
          type: session.type,
          reason: session.reason,
          timestamp: session.timestamp,
          status: session.status
        });
      }
    }

    return stats;
  }

  // Standard User Authentication Methods
  async registerUser(username, email, password, role = 'user') {
    try {
      // Check if user already exists
      const existingUser = await this.getUserByUsername(username);
      if (existingUser) {
        throw new Error('Username already exists');
      }

      const existingEmail = await this.getUserByEmail(email);
      if (existingEmail) {
        throw new Error('Email already exists');
      }

      // Hash password
      const saltRounds = 12;
      const hashedPassword = await bcrypt.hash(password, saltRounds);

      // Create user object
      const user = {
        id: this.generateUserId(),
        username,
        email,
        password: hashedPassword,
        role,
        createdAt: new Date().toISOString(),
        lastLogin: null,
        isActive: true,
        loginAttempts: 0,
        lockoutUntil: null,
        mfaEnabled: false,
        mfaSecret: null
      };

      // Save user (in production, use database)
      await this.saveUser(user);

      // Log registration
      authLogger.info('USER REGISTERED', {
        userId: user.id,
        username,
        email,
        role,
        timestamp: user.createdAt
      });

      return {
        success: true,
        userId: user.id,
        message: 'User registered successfully'
      };
    } catch (error) {
      authLogger.error('USER REGISTRATION FAILED', {
        username,
        email,
        error: error.message
      });
      throw error;
    }
  }

  async authenticateUser(usernameOrEmail, password) {
    try {
      // Get user by username or email
      let user = await this.getUserByUsername(usernameOrEmail);
      if (!user) {
        user = await this.getUserByEmail(usernameOrEmail);
      }

      if (!user) {
        throw new Error('Invalid credentials');
      }

      // Check if account is locked
      if (user.lockoutUntil && new Date() < new Date(user.lockoutUntil)) {
        throw new Error('Account is temporarily locked due to too many failed attempts');
      }

      // Verify password
      const isValidPassword = await bcrypt.compare(password, user.password);
      if (!isValidPassword) {
        await this.recordFailedLoginAttempt(user.id);
        throw new Error('Invalid credentials');
      }

      // Check if account is active
      if (!user.isActive) {
        throw new Error('Account is deactivated');
      }

      // Reset login attempts on successful login
      await this.resetLoginAttempts(user.id);

      // Update last login
      user.lastLogin = new Date().toISOString();
      await this.updateUser(user);

      // Generate JWT token
      const token = jwt.sign(
        {
          userId: user.id,
          username: user.username,
          email: user.email,
          role: user.role
        },
        process.env.JWT_SECRET || 'your_jwt_secret_key',
        { expiresIn: '24h' }
      );

      // Log successful login
      authLogger.info('USER LOGIN SUCCESSFUL', {
        userId: user.id,
        username: user.username,
        timestamp: new Date().toISOString()
      });

      return {
        success: true,
        token,
        user: {
          id: user.id,
          username: user.username,
          email: user.email,
          role: user.role,
          lastLogin: user.lastLogin
        }
      };
    } catch (error) {
      authLogger.warn('USER LOGIN FAILED', {
        usernameOrEmail,
        error: error.message,
        timestamp: new Date().toISOString()
      });
      throw error;
    }
  }

  async changePassword(userId, currentPassword, newPassword) {
    try {
      const user = await this.getUserById(userId);
      if (!user) {
        throw new Error('User not found');
      }

      // Verify current password
      const isValidPassword = await bcrypt.compare(currentPassword, user.password);
      if (!isValidPassword) {
        throw new Error('Current password is incorrect');
      }

      // Validate new password strength
      if (!this.validatePasswordStrength(newPassword)) {
        throw new Error('New password does not meet strength requirements');
      }

      // Hash new password
      const saltRounds = 12;
      const hashedPassword = await bcrypt.hash(newPassword, saltRounds);

      // Update password
      user.password = hashedPassword;
      await this.updateUser(user);

      // Log password change
      authLogger.info('PASSWORD CHANGED', {
        userId,
        timestamp: new Date().toISOString()
      });

      return {
        success: true,
        message: 'Password changed successfully'
      };
    } catch (error) {
      authLogger.error('PASSWORD CHANGE FAILED', {
        userId,
        error: error.message
      });
      throw error;
    }
  }

  async enableMFA(userId) {
    try {
      const user = await this.getUserById(userId);
      if (!user) {
        throw new Error('User not found');
      }

      // Generate MFA secret
      const mfaSecret = crypto.randomBytes(32).toString('hex');

      user.mfaEnabled = true;
      user.mfaSecret = mfaSecret;
      await this.updateUser(user);

      authLogger.info('MFA ENABLED', {
        userId,
        timestamp: new Date().toISOString()
      });

      return {
        success: true,
        mfaSecret,
        message: 'MFA enabled successfully'
      };
    } catch (error) {
      authLogger.error('MFA ENABLEMENT FAILED', {
        userId,
        error: error.message
      });
      throw error;
    }
  }

  async verifyMFAToken(userId, token) {
    try {
      const user = await this.getUserById(userId);
      if (!user || !user.mfaEnabled || !user.mfaSecret) {
        throw new Error('MFA not enabled for this user');
      }

      // Simple token verification (in production, use proper TOTP)
      const expectedToken = crypto.createHmac('sha256', user.mfaSecret)
        .update(Math.floor(Date.now() / 30000).toString()) // 30-second window
        .digest('hex')
        .substring(0, 6);

      if (token !== expectedToken) {
        throw new Error('Invalid MFA token');
      }

      return { success: true, message: 'MFA token verified' };
    } catch (error) {
      authLogger.warn('MFA VERIFICATION FAILED', {
        userId,
        error: error.message
      });
      throw error;
    }
  }

  async deactivateUser(userId, adminUserId) {
    try {
      const user = await this.getUserById(userId);
      if (!user) {
        throw new Error('User not found');
      }

      // Check admin permissions
      if (!this.validateAdminPermissions(adminUserId)) {
        throw new Error('Insufficient permissions to deactivate user');
      }

      user.isActive = false;
      await this.updateUser(user);

      authLogger.info('USER DEACTIVATED', {
        userId,
        adminUserId,
        timestamp: new Date().toISOString()
      });

      return {
        success: true,
        message: 'User deactivated successfully'
      };
    } catch (error) {
      authLogger.error('USER DEACTIVATION FAILED', {
        userId,
        adminUserId,
        error: error.message
      });
      throw error;
    }
  }

  // Helper methods for user management
  generateUserId() {
    return `USER_${Date.now()}_${crypto.randomBytes(4).toString('hex').toUpperCase()}`;
  }

  async recordFailedLoginAttempt(userId) {
    const user = await this.getUserById(userId);
    if (user) {
      user.loginAttempts = (user.loginAttempts || 0) + 1;

      // Lock account after 5 failed attempts
      if (user.loginAttempts >= 5) {
        user.lockoutUntil = new Date(Date.now() + 30 * 60 * 1000).toISOString(); // 30 minutes
      }

      await this.updateUser(user);
    }
  }

  async resetLoginAttempts(userId) {
    const user = await this.getUserById(userId);
    if (user) {
      user.loginAttempts = 0;
      user.lockoutUntil = null;
      await this.updateUser(user);
    }
  }

  // User data persistence methods (in production, use database)
  async saveUser(user) {
    try {
      const usersPath = path.join(__dirname, '../data/users.json');
      let users = {};

      if (fs.existsSync(usersPath)) {
        users = JSON.parse(fs.readFileSync(usersPath, 'utf-8'));
      }

      users[user.id] = user;
      fs.writeFileSync(usersPath, JSON.stringify(users, null, 2), 'utf-8');
    } catch (error) {
      throw new Error(`Failed to save user: ${error.message}`);
    }
  }

  async getUserById(userId) {
    try {
      const usersPath = path.join(__dirname, '../data/users.json');
      if (!fs.existsSync(usersPath)) return null;

      const users = JSON.parse(fs.readFileSync(usersPath, 'utf-8'));
      return users[userId] || null;
    } catch (error) {
      return null;
    }
  }

  async getUserByUsername(username) {
    try {
      const usersPath = path.join(__dirname, '../data/users.json');
      if (!fs.existsSync(usersPath)) return null;

      const users = JSON.parse(fs.readFileSync(usersPath, 'utf-8'));
      return Object.values(users).find(user => user.username === username) || null;
    } catch (error) {
      return null;
    }
  }

  async getUserByEmail(email) {
    try {
      const usersPath = path.join(__dirname, '../data/users.json');
      if (!fs.existsSync(usersPath)) return null;

      const users = JSON.parse(fs.readFileSync(usersPath, 'utf-8'));
      return Object.values(users).find(user => user.email === email) || null;
    } catch (error) {
      return null;
    }
  }

  async updateUser(user) {
    await this.saveUser(user);
  }

  // Validate JWT token
  validateToken(token) {
    try {
      const decoded = jwt.verify(token, process.env.JWT_SECRET || 'your_jwt_secret_key');
      return { valid: true, user: decoded };
    } catch (error) {
      return { valid: false, error: error.message };
    }
  }

  // Rate limiting for override requests
  checkRateLimit(identifier) {
    const now = Date.now();
    const windowStart = now - OVERRIDE_CONFIG.RATE_LIMIT_WINDOW_MS;

    // Get or create rate limit data for this identifier
    let rateData = rateLimitStore.get(identifier);
    if (!rateData) {
      rateData = { requests: [], lastReset: now };
      rateLimitStore.set(identifier, rateData);
    }

    // Clean old requests outside the window
    rateData.requests = rateData.requests.filter(timestamp => timestamp > windowStart);

    // Check if under limit
    if (rateData.requests.length >= OVERRIDE_CONFIG.RATE_LIMIT_MAX_REQUESTS) {
      const oldestRequest = Math.min(...rateData.requests);
      const resetTime = oldestRequest + OVERRIDE_CONFIG.RATE_LIMIT_WINDOW_MS;
      return {
        allowed: false,
        resetTime: resetTime,
        remainingRequests: 0,
        resetInMs: resetTime - now
      };
    }

    // Add current request
    rateData.requests.push(now);

    return {
      allowed: true,
      resetTime: now + OVERRIDE_CONFIG.RATE_LIMIT_WINDOW_MS,
      remainingRequests: OVERRIDE_CONFIG.RATE_LIMIT_MAX_REQUESTS - rateData.requests.length,
      resetInMs: OVERRIDE_CONFIG.RATE_LIMIT_WINDOW_MS
    };
  }

  // Enhanced password validation with configurable requirements
  validatePasswordStrength(password) {
    if (password && password.length >= OVERRIDE_CONFIG.PASSWORD_MIN_LENGTH) {
      if (OVERRIDE_CONFIG.PASSWORD_REQUIRE_COMPLEXITY) {
        // At least 1 uppercase, 1 lowercase, 1 number, 1 special character
        const complexityRegex = /^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[@$!%*?&])[A-Za-z\d@$!%*?&]+$/;
        return complexityRegex.test(password);
      }

      return true;
    }

    return false;
  }

  // Enhanced MFA enforcement
  shouldEnforceMFA(user, action = 'login') {
    if (OVERRIDE_CONFIG.MFA_ENFORCEMENT_LEVEL === 'disabled') {
      return false;
    }

    if (OVERRIDE_CONFIG.MFA_ENFORCEMENT_LEVEL === 'required') {
      return true;
    }

    // Optional level - check user preference or role-based requirements
    if (user && user.role === 'admin') {
      return true; // Always require MFA for admins
    }

    return user && user.mfaEnabled;
  }

  // Session timeout validation
  validateSessionTimeout(sessionStartTime) {
    const now = new Date();
    const sessionAge = now - new Date(sessionStartTime);
    const maxAge = OVERRIDE_CONFIG.SESSION_TIMEOUT_MINUTES * 60 * 1000;

    return sessionAge < maxAge;
  }

  // Cleanup rate limit data periodically
  cleanupRateLimitData() {
    const now = Date.now();
    const cutoff = now - (OVERRIDE_CONFIG.RATE_LIMIT_WINDOW_MS * 2); // Keep 2x window for safety

    for (const [identifier, data] of rateLimitStore) {
      data.requests = data.requests.filter(timestamp => timestamp > cutoff);
      if (data.requests.length === 0) {
        rateLimitStore.delete(identifier);
      }
    }

    overrideLogger.info('Rate limit data cleaned up', {
      activeIdentifiers: rateLimitStore.size,
      timestamp: new Date().toISOString()
    });
  }
}

