// Configuration with enhanced security
const JWT_SECRET = process.env.JWT_SECRET || crypto.randomBytes(64).toString('hex');
const JWT_REFRESH_SECRET = process.env.JWT_REFRESH_SECRET || crypto.randomBytes(64).toString('hex');
const MFA_SECRET = process.env.MFA_SECRET || crypto.randomBytes(32).toString('hex');
const ADMIN_OVERRIDE_CODE = process.env.ADMIN_OVERRIDE_CODE || 'OSCAR_BROOME_EMERGENCY_2024';

// Enhanced security settings
const PASSWORD_MIN_LENGTH = Number.parseInt(process.env.PASSWORD_MIN_LENGTH) || 12;
const PASSWORD_REQUIRE_UPPERCASE = process.env.PASSWORD_REQUIRE_UPPERCASE !== 'false';
const PASSWORD_REQUIRE_LOWERCASE = process.env.PASSWORD_REQUIRE_LOWERCASE !== 'false';
const PASSWORD_REQUIRE_NUMBERS = process.env.PASSWORD_REQUIRE_NUMBERS !== 'false';
const PASSWORD_REQUIRE_SPECIAL = process.env.PASSWORD_REQUIRE_SPECIAL !== 'false';
const SESSION_TIMEOUT = Number.parseInt(process.env.SESSION_TIMEOUT) || 3600000; // 1 hour
const MAX_SESSIONS_PER_USER = Number.parseInt(process.env.MAX_SESSIONS_PER_USER) || 5;

// In-memory user store (in production, use database)
const users = new Map();
const sessions = new Map();
const overrideCodes = new Map();

// Rate limiting
const loginAttempts = new Map();
const MAX_LOGIN_ATTEMPTS = 5;
const LOCKOUT_TIME = 15 * 60 * 1000; // 15 minutes

class AuthenticationManager {
  constructor() {
    this.initializeDefaultUsers();
  }

  async initializeDefaultUsers() {
    // Create default admin user
    const adminPassword = await bcrypt.hash('OscarBroome2024!', 12);
    users.set('admin@oscarbroomerevenue.com', {
      id: 'admin-001',
      email: 'admin@oscarbroomerevenue.com',
      password: adminPassword,
      role: 'admin',
      mfaEnabled: true,
      mfaSecret: MFA_SECRET,
      lastLogin: null,
      loginAttempts: 0,
      locked: false,
      permissions: ['read', 'write', 'delete', 'admin']
    });

    // Create executive user
    const execPassword = await bcrypt.hash('Executive2024!', 12);
    users.set('executive@oscarbroomerevenue.com', {
      id: 'exec-001',
      email: 'executive@oscarbroomerevenue.com',
      password: execPassword,
      role: 'executive',
      mfaEnabled: true,
      mfaSecret: crypto.randomBytes(32).toString('hex'),
      lastLogin: null,
      loginAttempts: 0,
      locked: false,
      permissions: ['read', 'write']
    });

    authLogger.info('Default users initialized');
  }

  async authenticateUser(email, password, mfaCode = null) {
    try {
      // Check rate limiting
      if (this.isAccountLocked(email)) {
        authLogger.warn(`Login attempt for locked account: ${email}`);
        return { success: false, message: 'Account is temporarily locked due to too many failed attempts' };
      }

      const user = users.get(email);
      if (!user) {
        authLogger.warn(`Login attempt for non-existent user: ${email}`);
        this.recordFailedAttempt(email);
        return { success: false, message: 'Invalid credentials' };
      }

      // Verify password
      const isValidPassword = await bcrypt.compare(password, user.password);
      if (!isValidPassword) {
        authLogger.warn(`Invalid password for user: ${email}`);
        this.recordFailedAttempt(email);
        return { success: false, message: 'Invalid credentials' };
      }

      // Check MFA if enabled
      if (user.mfaEnabled) {
        if (!mfaCode) {
          return { success: false, message: 'MFA code required', requiresMfa: true };
        }

        const isValidMfa = this.verifyMfaCode(user.mfaSecret, mfaCode);
        if (!isValidMfa) {
          authLogger.warn(`Invalid MFA code for user: ${email}`);
          this.recordFailedAttempt(email);
          return { success: false, message: 'Invalid MFA code' };
        }
      }

      // Reset login attempts on successful login
      user.loginAttempts = 0;
      user.lastLogin = new Date();
      users.set(email, user);

      // Generate tokens
      const tokens = this.generateTokens(user);

      // Store session
      sessions.set(tokens.accessToken, {
        userId: user.id,
        email: user.email,
        role: user.role,
        permissions: user.permissions,
        expiresAt: Date.now() + (15 * 60 * 1000) // 15 minutes
      });

      authLogger.info(`Successful login for user: ${email}`);
      return {
        success: true,
        message: 'Login successful',
        user: {
          id: user.id,
          email: user.email,
          role: user.role,
          permissions: user.permissions
        },
        tokens
      };

    } catch (error) {
      authLogger.error(`Authentication error for ${email}: ${error.message}`);
      throw error; // Re-throw to allow caller to handle
    }
  }

  async adminOverride(overrideCode, targetEmail) {
    try {
      if (overrideCode !== ADMIN_OVERRIDE_CODE) {
        overrideLogger.warn(`Invalid admin override code attempt`);
        return { success: false, message: 'Invalid override code' };
      }

      const user = users.get(targetEmail);
      if (!user) {
        overrideLogger.warn(`Admin override for non-existent user: ${targetEmail}`);
        return { success: false, message: 'User not found' };
      }

      // Reset user account
      user.loginAttempts = 0;
      user.locked = false;
      users.set(targetEmail, user);

      // Generate emergency access token
      const emergencyToken = jwt.sign(
        {
          userId: user.id,
          email: user.email,
          role: user.role,
          permissions: user.permissions,
          override: true,
          emergency: true
        },
        JWT_SECRET,
        { expiresIn: '1h' }
      );

      overrideLogger.info(`Admin override successful for user: ${targetEmail}`);
      return {
        success: true,
        message: 'Admin override successful',
        emergencyToken,
        user: {
          id: user.id,
          email: user.email,
          role: user.role
        }
      };

    } catch (error) {
      overrideLogger.error(`Admin override error: ${error.message}`);
      return { success: false, message: 'Override failed' };
    }
  }

  generateTokens(user) {
    const accessToken = jwt.sign(
      {
        userId: user.id,
        email: user.email,
        role: user.role,
        permissions: user.permissions
      },
      JWT_SECRET,
      { expiresIn: '15m' }
    );

    const refreshToken = jwt.sign(
      {
        userId: user.id,
        email: user.email,
        type: 'refresh'
      },
      JWT_REFRESH_SECRET,
      { expiresIn: '7d' }
    );

    return { accessToken, refreshToken };
  }

  verifyToken(token) {
    try {
      const decoded = jwt.verify(token, JWT_SECRET);
      const session = sessions.get(token);

      if (!session || session.expiresAt < Date.now()) {
        return null;
      }

      return decoded;
    } catch (error) {
      return null;
    }
  }

  verifyMfaCode(secret, code) {
    // Simple TOTP implementation (in production, use a proper TOTP library)
    const timeWindow = Math.floor(Date.now() / 30000); // 30-second windows
    const expectedCode = crypto.createHmac('sha1', secret)
      .update(timeWindow.toString())
      .digest('hex')
      .substring(0, 6);

    return expectedCode === code;
  }

  recordFailedAttempt(email) {
    const attempts = loginAttempts.get(email) || { count: 0, lastAttempt: Date.now() };
    attempts.count += 1;
    attempts.lastAttempt = Date.now();

    if (attempts.count >= MAX_LOGIN_ATTEMPTS) {
      const user = users.get(email);
      if (user) {
        user.locked = true;
        user.lockedUntil = Date.now() + LOCKOUT_TIME;
        users.set(email, user);
        authLogger.warn(`Account locked for user: ${email}`);
      }
    }

    loginAttempts.set(email, attempts);
  }

  isAccountLocked(email) {
    const user = users.get(email);
    if (!user || !user.locked) return false;

    if (Date.now() > user.lockedUntil) {
      user.locked = false;
      users.set(email, user);
      return false;
    }

    return true;
  }

  async refreshToken(refreshToken) {
    try {
      const decoded = jwt.verify(refreshToken, JWT_REFRESH_SECRET);
      const user = users.get(decoded.email);

      if (!user) {
        return { success: false, message: 'User not found' };
      }

      const tokens = this.generateTokens(user);
      return { success: true, tokens };
    } catch (error) {
      authLogger.error(`Refresh token error: ${error.message}`);
      return { success: false, message: 'Invalid refresh token' };
    }
  }

  logout(token) {
    sessions.delete(token);
    authLogger.info('User logged out');
    return { success: true, message: 'Logged out successfully' };
  }

  getUserProfile(email) {
    const user = users.get(email);
    if (!user) return null;

    return {
      id: user.id,
      email: user.email,
      role: user.role,
      permissions: user.permissions,
      lastLogin: user.lastLogin,
      mfaEnabled: user.mfaEnabled
    };
  }

  // Enhanced password validation
  validatePassword(password) {
    if (!password || password.length < PASSWORD_MIN_LENGTH) {
      return { valid: false, message: `Password must be at least ${PASSWORD_MIN_LENGTH} characters long` };
    }

    if (PASSWORD_REQUIRE_UPPERCASE && !/[A-Z]/.test(password)) {
      return { valid: false, message: 'Password must contain at least one uppercase letter' };
    }

    if (PASSWORD_REQUIRE_LOWERCASE && !/[a-z]/.test(password)) {
      return { valid: false, message: 'Password must contain at least one lowercase letter' };
    }

    if (PASSWORD_REQUIRE_NUMBERS && !/\d/.test(password)) {
      return { valid: false, message: 'Password must contain at least one number' };
    }

    if (PASSWORD_REQUIRE_SPECIAL && !/[!@#$%^&*()_+\-={}|;:,.<>?`~]/.test(password)) {
      return { valid: false, message: 'Password must contain at least one special character' };
    }

    return { valid: true, message: 'Password is valid' };
  }

  // Session management
  getActiveSessions(userId) {
    const userSessions = [];
    for (const [token, session] of sessions.entries()) {
      if (session.userId === userId && session.expiresAt > Date.now()) {
        userSessions.push({
          token: token.substring(0, 10) + '...', // Partial token for security
          expiresAt: session.expiresAt,
          createdAt: session.expiresAt - (15 * 60 * 1000) // Approximate creation time
        });
      }
    }
    return userSessions;
  }

  // Force logout all sessions for a user
  forceLogoutAll(userId) {
    const tokensToDelete = [];
    for (const [token, session] of sessions.entries()) {
      if (session.userId === userId) {
        tokensToDelete.push(token);
      }
    }

    for (const token of tokensToDelete) {
      sessions.delete(token);
    }
    authLogger.info(`Force logout all sessions for user: ${userId}`);
    return { success: true, message: `${tokensToDelete.length} sessions terminated` };
  }

  // Enhanced token verification with session cleanup
  verifyTokenEnhanced(token) {
    try {
      const decoded = jwt.verify(token, JWT_SECRET);
      const session = sessions.get(token);

      if (!session) {
        return { valid: false, message: 'Session not found' };
      }

      if (session.expiresAt < Date.now()) {
        sessions.delete(token); // Clean up expired session
        return { valid: false, message: 'Session expired' };
      }

      // Check if user still exists and is not locked
      const user = users.get(session.email);
      if (!user || user.locked) {
        sessions.delete(token);
        return { valid: false, message: 'User account is locked or inactive' };
      }

      return {
        valid: true,
        decoded,
        session,
        user: {
          id: user.id,
          email: user.email,
          role: user.role,
          permissions: user.permissions
        }
      };
    } catch (error) {
      if (sessions.has(token)) {
        sessions.delete(token); // Clean up invalid session
      }
      authLogger.error(`Token verification error: ${error.message}`);
      return { valid: false, message: 'Invalid token' };
    }
  }

  // Security audit methods
  getSecurityStats() {
    const totalUsers = users.size;
    const lockedUsers = Array.from(users.values()).filter(user => user.locked).length;
    const activeSessions = Array.from(sessions.values()).filter(session => session.expiresAt > Date.now()).length;
    const failedAttempts = Array.from(loginAttempts.values()).filter(attempt => attempt.count > 0).length;

    return {
      totalUsers,
      lockedUsers,
      activeSessions,
      failedAttempts,
      timestamp: new Date().toISOString()
    };
  }

  // Clean up expired sessions (should be called periodically)
  cleanupExpiredSessions() {
    const now = Date.now();
    let cleaned = 0;

    for (const [token, session] of sessions.entries()) {
      if (session.expiresAt < now) {
        sessions.delete(token);
        cleaned++;
      }
    }

    if (cleaned > 0) {
      authLogger.info(`Cleaned up ${cleaned} expired sessions`);
    }

    return { cleaned };
  }
}

