      /javascript:/i,
      /on\w+\s*=/i,
      /union\s+select/i,
      /drop\s+table/i,
      /\bor\b\s+\d+\s*=\s*\d+|\band\b\s+\d+\s*=\s*\d+/i,
      /--/g,
      /\/\*.*\*\//g
    ];

    return suspiciousPatterns.some(pattern => pattern.test(value));
  }

  validateRequestBody(body) {
    const errors = [];

    // Email validation
    if (body.email && !VALIDATION_PATTERNS.EMAIL.test(body.email)) {
      errors.push('Invalid email format');
    }

    // Password validation
    if (body.password && !VALIDATION_PATTERNS.PASSWORD.test(body.password)) {
      errors.push('Password must be at least 12 characters with uppercase, lowercase, number, and special character');
    }

    // Amount validation
    if (body.amount && !VALIDATION_PATTERNS.AMOUNT.test(body.amount.toString())) {
      errors.push('Invalid amount format');
    }

    // Phone validation
    if (body.phone && !VALIDATION_PATTERNS.PHONE.test(body.phone)) {
      errors.push('Invalid phone number format');
    }

    return {
      valid: errors.length === 0,
      errors
    };
  }

  sanitizeString(str) {
    if (typeof str !== 'string') return str;

    return str
      .replace(/<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi, '')
      .replace(/javascript:/gi, '')
      .replace(/on\w+\s*=/gi, '')
      .replace(/<[^>]*>/g, '')
      .trim();
  }

  sanitizeObject(obj) {
    if (obj === null || typeof obj !== 'object') return obj;

    if (Array.isArray(obj)) {
      return obj.map(item => this.sanitizeObject(item));
    }

    const sanitized = {};
    for (const [key, value] of Object.entries(obj)) {
      if (typeof value === 'string') {
        sanitized[key] = this.sanitizeString(value);
      } else if (typeof value === 'object') {
        sanitized[key] = this.sanitizeObject(value);
      } else {
        sanitized[key] = value;
      }
    }

    return sanitized;
  }

  recordSuspiciousActivity(req) {
    const clientIP = this.getClientIP(req);
    const activity = this.suspiciousActivities.get(clientIP) || {
      count: 0,
      lastActivity: new Date(),
      activities: []
    };

    activity.count++;
    activity.lastActivity = new Date();
    activity.activities.push({
      timestamp: new Date(),
      path: req.path,
      method: req.method,
      userAgent: req.headers['user-agent']
    });

    // Keep only last 10 activities
    if (activity.activities.length > 10) {
      activity.activities = activity.activities.slice(-10);
    }

    this.suspiciousActivities.set(clientIP, activity);

    securityLogger.warn(`Suspicious activity recorded for IP: ${clientIP}`);
  }

  // Get security metrics
  getSecurityMetrics() {
    return {
      activeRateLimits: this.requestCounts.size,
      suspiciousActivities: this.suspiciousActivities.size,
      totalRequests: Array.from(this.requestCounts.values()).reduce((sum, data) => sum + data.count, 0)
    };
  }
}

// Export middleware functions
const securityMiddleware = new SecurityMiddleware();

module.exports = {
  SecurityMiddleware,
  securityMiddleware,
  rateLimit: (req, res, next) => securityMiddleware.rateLimit(req, res, next),
  securityHeaders: (req, res, next) => securityMiddleware.securityHeaders(req, res, next),
  cors: (req, res, next) => securityMiddleware.cors(req, res, next),
  validateInput: (req, res, next) => securityMiddleware.validateInput(req, res, next),
  sanitizeInput: (req, res, next) => securityMiddleware.sanitizeInput(req, res, next),
  getSecurityMetrics: () => securityMiddleware.getSecurityMetrics()
};

import mongoose from 'mongoose';
import bcrypt from 'bcryptjs';

const tenantSchema = new mongoose.Schema({
  tenantId: {
    type: String,
    required: true,
    unique: true,
    index: true
  },
  name: {
    type: String,
    required: true,
    trim: true
  },
  domain: {
    type: String,
    required: true,
    unique: true,
    lowercase: true,
    trim: true
  },
  description: {
    type: String,
    trim: true
  },
  status: {
    type: String,
    enum: ['active', 'suspended', 'inactive'],
    default: 'active'
  },
  settings: {
    timezone: {
      type: String,
      default: 'UTC'
    },
    currency: {
      type: String,
      default: 'USD'
    },
    features: {
      payroll: { type: Boolean, default: true },
      merchant: { type: Boolean, default: true },
      jpmorgan: { type: Boolean, default: true },
      analytics: { type: Boolean, default: true },
      blockchain: { type: Boolean, default: true }
    },
    limits: {
      maxUsers: { type: Number, default: 100 },
      maxTransactions: { type: Number, default: 10000 },
      storageLimit: { type: Number, default: 1073741824 } // 1GB in bytes
    }
  },
  contact: {
    email: {
      type: String,
      required: true,
      lowercase: true,
      trim: true
    },
    phone: {
      type: String,
      trim: true
    },
    address: {
      street: String,
      city: String,
      state: String,
      zipCode: String,
      country: String
    }
  },
  subscription: {
    plan: {
      type: String,
      enum: ['starter', 'professional', 'enterprise'],
      default: 'professional'
    },
    status: {
      type: String,
      enum: ['trial', 'active', 'expired', 'cancelled'],
      default: 'trial'
    },
    startDate: {
      type: Date,
      default: Date.now
    },
    endDate: {
      type: Date
    },
    autoRenew: {
      type: Boolean,
      default: true
    }
  },
  apiKeys: [{
    key: {
      type: String,
      required: true
    },
    name: {
      type: String,
      required: true
    },
    permissions: [{
      type: String,
      enum: ['read', 'write', 'admin']
    }],
    createdAt: {
      type: Date,
      default: Date.now
    },
    lastUsed: Date,
    isActive: {
      type: Boolean,
      default: true
    }
  }],
  audit: {
    createdBy: {
      type: String,
      required: true
    },
    createdAt: {
      type: Date,
      default: Date.now
    },
    updatedBy: String,
    updatedAt: Date,
    lastActivity: Date
  }
}, {
  timestamps: true,
  toJSON: { virtuals: true },
  toObject: { virtuals: true }
});

// Indexes for performance
tenantSchema.index({ domain: 1 });
tenantSchema.index({ status: 1 });
tenantSchema.index({ 'subscription.status': 1 });
tenantSchema.index({ 'subscription.endDate': 1 });

// Virtual for subscription status
tenantSchema.virtual('isSubscriptionActive').get(function() {
  return this.subscription.status === 'active' ||
         (this.subscription.status === 'trial' && this.subscription.endDate > new Date());
});

// Virtual for usage statistics
tenantSchema.virtual('usageStats').get(async function() {
  const User = mongoose.model('User');
  const Transaction = mongoose.model('Transaction');

  const [userCount, transactionCount] = await Promise.all([
    User.countDocuments({ tenantId: this.tenantId }),
    Transaction.countDocuments({ tenantId: this.tenantId })
  ]);

  return {
    users: userCount,
    transactions: transactionCount,
    userLimit: this.settings.limits.maxUsers,
    transactionLimit: this.settings.limits.maxTransactions
  };
});

// Pre-save middleware to hash API keys
tenantSchema.pre('save', async function(next) {
  if (this.isModified('apiKeys')) {
    for (const apiKey of this.apiKeys) {
      if (apiKey.key && !apiKey.key.startsWith('$2a$')) {
        apiKey.key = await bcrypt.hash(apiKey.key, 12);
      }
    }
  }
  next();
});

// Instance methods
tenantSchema.methods = {
  // Verify API key
  async verifyApiKey(key) {
    for (const apiKey of this.apiKeys) {
      if (apiKey.isActive && await bcrypt.compare(key, apiKey.key)) {
        apiKey.lastUsed = new Date();
        await this.save();
        return { valid: true, permissions: apiKey.permissions, name: apiKey.name };
      }
    }
    return { valid: false };
  },

  // Check feature access
  hasFeature(feature) {
    return this.settings.features[feature] === true;
  },

  // Check limits
  async checkLimits(type) {
    const stats = await this.getUsageStats();
    const limit = this.settings.limits[type + 'Limit'];
    const current = stats[type + 's'];

    return {
      current,
      limit,
      remaining: Math.max(0, limit - current),
      exceeded: current >= limit
    };
  },

  // Get usage statistics
  async getUsageStats() {
    const User = mongoose.model('User');
    const Transaction = mongoose.model('Transaction');

    const [userCount, transactionCount] = await Promise.all([
      User.countDocuments({ tenantId: this.tenantId }),
      Transaction.countDocuments({ tenantId: this.tenantId })
    ]);

    return {
      users: userCount,
      transactions: transactionCount,
      userLimit: this.settings.limits.maxUsers,
      transactionLimit: this.settings.limits.maxTransactions
    };
  },

  // Suspend tenant
  suspend(reason) {
    this.status = 'suspended';
    this.audit.updatedAt = new Date();
    this.audit.updatedBy = 'system';
    return this.save();
  },

  // Reactivate tenant
  reactivate() {
    this.status = 'active';
    this.audit.updatedAt = new Date();
    this.audit.updatedBy = 'system';
    return this.save();
  }
};

// Static methods
tenantSchema.statics = {
  // Find tenant by domain
  findByDomain(domain) {
    return this.findOne({ domain: domain.toLowerCase(), status: 'active' });
  },

  // Find tenants with expired subscriptions
  findExpiredSubscriptions() {
    return this.find({
      'subscription.status': { $in: ['trial', 'active'] },
      'subscription.endDate': { $lt: new Date() }
    });
  },

  // Create default tenant
  async createDefaultTenant() {
    const defaultTenant = {
      tenantId: 'default',
      name: 'Oscar Broome Revenue',
      domain: 'oscarbroome.com',
      description: 'Default tenant for Oscar Broome Revenue system',
      contact: {
        email: 'admin@oscarbroome.com'
      },
      settings: {
        features: {
          payroll: true,
          merchant: true,
          jpmorgan: true,
          analytics: true,
          blockchain: true
        }
      },
      audit: {
        createdBy: 'system'
      }
    };

    return this.findOneAndUpdate(
      { tenantId: 'default' },
      defaultTenant,
      { upsert: true, new: true }
    );
  }
};

const Tenant = mongoose.model('Tenant', tenantSchema);

export default Tenant;

#!/usr/bin/env node

const fs = require('fs');
const path = require('path');
const { execSync } = require('child_process');

console.log('🚀 OSCAR BROOME REVENUE - Production Deployment Script');
console.log('====================================================\n');

// Configuration
const CONFIG = {
  requiredEnvVars: [
    'STRIPE_SECRET_KEY',
    'SMTP_HOST',
    'SMTP_USER',
    'SMTP_PASS',
    'TWILIO_ACCOUNT_SID',
    'TWILIO_AUTH_TOKEN',
    'TWILIO_PHONE_NUMBER'
  ],
  optionalEnvVars: [
    'NODE_ENV',
    'PORT',
    'SMTP_PORT'
  ],
  productionDefaults: {
    NODE_ENV: 'production',
    PORT: '3000',
    SMTP_PORT: '587'
  }
};

class ProductionDeployer {
  constructor() {
    this.errors = [];
    this.warnings = [];
  }

  log(message, type = 'info') {
    const timestamp = new Date().toISOString();
    const prefix = {
      info: 'ℹ️ ',
      success: '✅ ',
      warning: '⚠️ ',
      error: '❌ ',
      step: '🔧 '
    }[type] || '📝 ';

    console.log(`[${timestamp}] ${prefix}${message}`);
  }

  async run() {
    try {
      this.log('Starting production deployment process...', 'step');

      await this.checkEnvironment();
      await this.validateDependencies();
      await this.setupEnvironment();
      await this.validateConfiguration();
      await this.runPreFlightChecks();
      await this.startProductionServer();

      this.log('Production deployment completed successfully!', 'success');

    } catch (error) {
      this.log(`Deployment failed: ${error.message}`, 'error');
      this.errors.push(error.message);
      process.exit(1);
    }
  }

  async checkEnvironment() {
    this.log('Checking system environment...', 'step');

    // Check Node.js version
    const nodeVersion = process.version;
    this.log(`Node.js version: ${nodeVersion}`);

    if (!nodeVersion.startsWith('v14.') && !nodeVersion.startsWith('v16.') && !nodeVersion.startsWith('v18.') && !nodeVersion.startsWith('v20.')) {
      throw new Error(`Unsupported Node.js version: ${nodeVersion}. Please use Node.js 14, 16, 18, or 20.`);
    }

    // Check if we're in the right directory
    if (!fs.existsSync('package.json')) {
      throw new Error('package.json not found. Please run this script from the project root directory.');
    }

    // Check if merchant_bill_pay.js exists
    if (!fs.existsSync('earnings_dashboard/merchant_bill_pay.js')) {
      throw new Error('merchant_bill_pay.js not found. Please ensure the merchant bill pay system is properly installed.');
    }

    this.log('System environment check passed', 'success');
  }

  async validateDependencies() {
    this.log('Validating dependencies...', 'step');

    try {
      // Check if node_modules exists
      if (!fs.existsSync('node_modules')) {
        this.log('Installing dependencies...', 'step');
        execSync('npm install', { stdio: 'inherit' });
      }

      // Validate critical dependencies
      const packageJson = JSON.parse(fs.readFileSync('package.json', 'utf8'));
      const requiredDeps = ['express', 'stripe', 'nodemailer', 'twilio', 'dotenv'];

      for (const dep of requiredDeps) {
        if (!packageJson.dependencies[dep]) {
          throw new Error(`Required dependency '${dep}' not found in package.json`);
        }
      }

      this.log('Dependencies validation passed', 'success');

    } catch (error) {
      throw new Error(`Dependency validation failed: ${error.message}`);
    }
  }

  async setupEnvironment() {
    this.log('Setting up production environment...', 'step');

    // Create .env file if it doesn't exist
    if (!fs.existsSync('.env')) {
      this.log('Creating .env file from template...', 'step');

      let envContent = '# Production Environment Variables\n';
      envContent += '# Generated by production_deploy.js\n\n';

      // Add production defaults
      Object.entries(CONFIG.productionDefaults).forEach(([key, value]) => {
        envContent += `${key}=${value}\n`;
      });

      // Add placeholders for required variables
      CONFIG.requiredEnvVars.forEach(varName => {
        if (!CONFIG.productionDefaults[varName]) {
          envContent += `# ${varName}=your_${varName.toLowerCase()}_here\n`;
        }
      });

      fs.writeFileSync('.env', envContent);
      this.log('.env file created. Please configure your credentials.', 'warning');
    }

    // Create logs directory
    if (!fs.existsSync('logs')) {
      fs.mkdirSync('logs');
      this.log('Logs directory created');
    }

    this.log('Environment setup completed', 'success');
  }

  async validateConfiguration() {
    this.log('Validating configuration...', 'step');

    // Load environment variables
    require('dotenv').config();

    const missingRequired = [];
    const missingOptional = [];

    // Check required environment variables
    CONFIG.requiredEnvVars.forEach(varName => {
      if (!process.env[varName] || process.env[varName].startsWith('your_')) {
        missingRequired.push(varName);
      }
    });

    // Check optional environment variables
    CONFIG.optionalEnvVars.forEach(varName => {
      if (!process.env[varName]) {
        missingOptional.push(varName);
      }
    });

    if (missingRequired.length > 0) {
      this.log(`Missing required environment variables: ${missingRequired.join(', ')}`, 'error');
      this.log('Please configure these variables in your .env file', 'warning');
      this.log('You can use the setup_credentials.js script to configure them interactively', 'info');
    }

    if (missingOptional.length > 0) {
      this.log(`Missing optional environment variables (using defaults): ${missingOptional.join(', ')}`, 'warning');
    }

    if (missingRequired.length === 0) {
      this.log('Configuration validation passed', 'success');
    } else {
      this.warnings.push('Some required configuration is missing');
    }
  }

  async runPreFlightChecks() {
    this.log('Running pre-flight checks...', 'step');

    try {
      // Test module imports
      const merchantBillPay = require('./earnings_dashboard/merchant_bill_pay');
      this.log('Merchant bill pay module loaded successfully');

      // Check if all required functions exist
      const requiredFunctions = [
        'createMerchantPaymentIntent',
        'handleMerchantWebhook',
        'sendMerchantPaymentSuccessNotification',
        'sendMerchantPaymentFailureNotification',
        'sendSMSNotification',
        'getMerchantEmail',
        'getMerchantPhone'
      ];

      const missingFunctions = [];
      requiredFunctions.forEach(funcName => {
        if (typeof merchantBillPay[funcName] !== 'function') {
          missingFunctions.push(funcName);
        }
      });

      if (missingFunctions.length > 0) {
        throw new Error(`Missing required functions: ${missingFunctions.join(', ')}`);
      }

      this.log('All required functions are available', 'success');

      // Test merchant data
      const testMerchant = merchantBillPay.getMerchantEmail('merchant_001');
      if (testMerchant) {
        this.log('Merchant data loaded successfully');
      } else {
        this.log('Merchant data not found - using mock data', 'warning');
      }

    } catch (error) {
      throw new Error(`Pre-flight check failed: ${error.message}`);
    }

    this.log('Pre-flight checks completed', 'success');
  }

  async startProductionServer() {
    this.log('Starting production server...', 'step');

    const port = process.env.PORT || 3000;
    const nodeEnv = process.env.NODE_ENV || 'production';

    this.log(`Environment: ${nodeEnv}`);
    this.log(`Port: ${port}`);

    // Check if port is available
    const net = require('net');
    const server = net.createServer();

    return new Promise((resolve, reject) => {
      server.listen(port, (err) => {
        server.close();

        if (err) {
          reject(new Error(`Port ${port} is not available`));
          return;
        }

        this.log(`Port ${port} is available`, 'success');

        // Start the server
        this.log('Starting server with PM2...', 'step');

        try {
          // Check if PM2 is available
          execSync('pm2 --version', { stdio: 'pipe' });

          // Use PM2 for production
          execSync('pm2 stop oscar-broome-revenue || true', { stdio: 'pipe' });
          execSync('pm2 delete oscar-broome-revenue || true', { stdio: 'pipe' });
          execSync('pm2 start server-enhanced.js --name oscar-broome-revenue', { stdio: 'inherit' });
          execSync('pm2 save', { stdio: 'pipe' });

          this.log('Server started with PM2 process manager', 'success');
          this.log('Use "pm2 logs oscar-broome-revenue" to view logs', 'info');
          this.log('Use "pm2 monit" to monitor the application', 'info');

        } catch (pm2Error) {
          this.log('PM2 not available, starting server directly...', 'warning');

          // Fallback to direct node execution
          const { spawn } = require('child_process');
          const serverProcess = spawn('node', ['server-enhanced.js'], {
            detached: true,
            stdio: 'ignore'
          });

          serverProcess.unref();
          this.log('Server started directly with Node.js', 'success');
          this.log(`Process ID: ${serverProcess.pid}`, 'info');
        }

        // Wait a moment for server to start
        setTimeout(() => {
          this.log(`🚀 Server should be running at http://localhost:${port}`, 'success');
          resolve();
        }, 2000);

      });
    });
  }

  showSummary() {
    console.log('\n📊 DEPLOYMENT SUMMARY');
    console.log('====================');

    if (this.errors.length > 0) {
      console.log('\n❌ ERRORS:');
      this.errors.forEach(error => console.log(`   - ${error}`));
    }

    if (this.warnings.length > 0) {
      console.log('\n⚠️  WARNINGS:');
      this.warnings.forEach(warning => console.log(`   - ${warning}`));
    }

    console.log('\n✅ COMPLETED STEPS:');
    console.log('   - Environment validation');
    console.log('   - Dependency installation');
    console.log('   - Configuration setup');
    console.log('   - Pre-flight checks');
    console.log('   - Production server startup');

    console.log('\n🔧 NEXT STEPS:');
    console.log('   1. Configure your production credentials in .env');
    console.log('   2. Set up SSL certificates for HTTPS');
    console.log('   3. Configure reverse proxy (nginx recommended)');
    console.log('   4. Set up monitoring and alerting');
    console.log('   5. Configure backup and recovery procedures');

    console.log('\n📝 USEFUL COMMANDS:');
    console.log('   - View logs: pm2 logs oscar-broome-revenue');
    console.log('   - Monitor: pm2 monit');
    console.log('   - Restart: pm2 restart oscar-broome-revenue');
    console.log('   - Stop: pm2 stop oscar-broome-revenue');
  }
}

// Run the deployment
const deployer = new ProductionDeployer();

deployer.run().then(() => {
  deployer.showSummary();
}).catch((error) => {
