    // For bi-weekly payroll, determine which pay period
    const payPeriodNumber = Math.ceil(day / 14);
    return `${year}-${month.toString().padStart(2, '0')}-P${payPeriodNumber}`;
  }

  async calculateEmployeePayroll(employee, payPeriod) {
