import express from 'express';
import authService from '../services/authService.js';
import {
  authenticate,
  authRateLimit,
  logAuthEvent,
  validateAuthRequest
} from '../middleware/auth.js';

const router = express.Router();

// Register new user
router.post('/register', authRateLimit, logAuthEvent('register'), async (req, res) => {
  try {
    const { username, email, password, firstName, lastName, role, tenantId } = req.body;

    // Basic validation
    if (!username || !email || !password || !firstName || !lastName || !tenantId) {
      return res.status(400).json({
        success: false,
        message: 'All fields including tenantId are required'
      });
    }

    if (password.length < 6) {
      return res.status(400).json({
        success: false,
        message: 'Password must be at least 6 characters long'
      });
    }

    const result = await authService.register({
      username,
      email,
      password,
      firstName,
      lastName,
      role: role || 'user',
      tenantId
    });

    res.status(201).json({
      success: true,
      message: 'User registered successfully',
      data: result
    });
  } catch (error) {
    console.error('Registration error:', error);
    res.status(400).json({
      success: false,
      message: error.message
    });
  }
});

// Login user
router.post('/login', authRateLimit, logAuthEvent('login'), async (req, res) => {
  try {
    const { username, password } = req.body;

    if (!username || !password) {
      return res.status(400).json({
        success: false,
        message: 'Username and password are required'
      });
    }

    const result = await authService.login({ username, password });

    res.json({
      success: true,
      message: 'Login successful',
      data: result
    });
  } catch (error) {
    console.error('Login error:', error);
    res.status(401).json({
      success: false,
      message: error.message
    });
  }
});

// Refresh access token
router.post('/refresh', logAuthEvent('refresh'), async (req, res) => {
  try {
    const { refreshToken } = req.body;

    if (!refreshToken) {
      return res.status(400).json({
        success: false,
        message: 'Refresh token is required'
      });
    }

    const tokens = await authService.refreshToken(refreshToken);

    res.json({
      success: true,
